public class FutureUtil {

    public static FutureCore submit(String arg){
        FutureCore futureCore = new FutureCore(arg);
        //子线程开始下载资源
        new Thread(new Runnable() {
            @Override
            public void run() {
                futureCore.setRequest();
            }
        }).start();
        //直接返回结果
        return futureCore;
    }
}

