//        synchronized (this){  //加一个判断 判断最后一张票的两个线程情况
  if(TrainCount>0){
      System.out.println(Thread.currentThread().getName()+"：正在出售第"+(100-TrainCount+1)+"张票");
      TrainCount--;
  }


//        }
    }

是和下面的功能是一样的

