 private  void sale(){ //this锁
        synchronized (ThreadTrain.class){
        //加一个判断 判断最后一张票的两个线程情况
        if(TrainCount>0){
            System.out.println(Thread.currentThread().getName()+"：正在出售第"+(100-TrainCount+1)+"张票");
            TrainCount--;
        }

